<template>
    <div style="width: 40%; margin-left: 200px">
        <div style="margin-bottom: 40px; margin-left: 280px" >新增图书</div>
        <el-form :rules="rules" ref="ruleForm" :model="ruleForm" label-width="200px">
            <el-form-item label="名称" prop="name">
                <el-input v-model="ruleForm.name" placeholder="请输入名称"></el-input>
            </el-form-item>
            <el-form-item label="作者" prop="author">
                <el-input v-model="ruleForm.author" placeholder="请输入作者"></el-input>
            </el-form-item>
            <el-form-item label="标准码" prop="bookNo">
                <el-input v-model="ruleForm.bookNo" placeholder="请输入标准码"></el-input>
            </el-form-item>
<!--          el-cascader中的value表示的是publish中的字段名-->
            <el-form-item label="出版社" prop="publish">
              <el-cascader
                  :props="{value: 'name', label: 'name'}"
                  v-model="ruleForm.publishes"
                  :options="publishes"
                  @change="handleChange"></el-cascader>
            </el-form-item>
          <el-form-item label="区域编号" prop="locationId">
            <el-cascader
                :props="{value: 'id', label: 'id'}"
                v-model="ruleForm.locations"
                :options="locations"
                @change="handleChange"></el-cascader>
          </el-form-item>

            <el-form-item label="数量" prop="number">
                <el-input v-model="ruleForm.number" placeholder="剩余数量"></el-input>
            </el-form-item>
            <el-form-item label="分类" prop="category">
                <el-cascader
                        :props="{value: 'name', label: 'name'}"
                        v-model="ruleForm.categories"
                        :options="categories"
                        @change="handleChange"></el-cascader>
            </el-form-item>
            <el-form-item label="描述" prop="description">
                <el-input type="textarea" v-model="ruleForm.description" placeholder="请输入描述"></el-input>
            </el-form-item>

        </el-form>
        <div style="text-align: center; margin-top: 30px;margin-left: 100px">
            <el-button type="primary" @click="save">提交</el-button>
            <el-button style="background-color: #f3d19e; color: white" @click="change">返回</el-button>
            <el-button type="" @click="save">提交</el-button>
<!--            <el-button type="danger ">取消</el-button>-->
        </div>
    </div>
</template>

<script>
    import request from "@/utils/request";
    import Cookies from "js-cookie";
    //导入请求
    export default {
        name: "AddBook",
        data(){
            return {
                admin: Cookies.get('admin') ? JSON.parse(Cookies.get('admin')) : {},
                ruleForm: {
                },
                categories:[],
                publishes: [],
                locations: [],
                rules: {
                    name: [
                        {required: true, message: '请输入图书名称', trigger: 'blur'},
                    ],
                }
            }

        },
        created() {
            request.get('/category/tree').then(res => {
                this.categories = res.data;
            })
            request.get('/publish/list').then(res => {
              this.publishes  = res.data
            })
          request.get('/location/list').then(res => {
            this.locations  = res.data
          })

        },
        methods: {
            handleCoverSuccess(res){
                if(res.code === '200'){
                    this.form.cover = res.data;
                    this.$set(this.ruleForm, 'cover', res.data);
                }
            },
            save() {
                this.$refs['ruleForm'].validate((valid) => {
                    if(valid){
                        request.post('/book/save',this.ruleForm).then(res =>{
                            if(res.code === '200'){
                                this.$notify.success('成功')
                                this.$refs['ruleForm'].resetFields();
                                this.$router.push('bookList');
                            }else{
                                this.$notify.error(res.msg)
                            }
                        })
                    }
                })

                //    对接的是后台的UserController.java文件的路径
            },
            handleChange(){

            },
            change(){
                this.$router.push('bookList');
            }

        }
    }

</script>

<style >

    .avatar-uploader .el-upload {
        border: 1px dashed #d9d9d9;
        border-radius: 6px;
        cursor: pointer;
        position: relative;
        overflow: hidden;
    }
    .avatar-uploader .el-upload:hover {
        border-color: #409EFF;
    }
    .avatar-uploader-icon {
        font-size: 28px;
        color: #8c939d;
        width: 178px;
        height: 178px;
        line-height: 178px;
        text-align: center;
    }
    .avatar {
        width: 178px;
        height: 178px;
        display: block;
    }

</style>